import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const Sidebar: React.FC = () => {
  const location = useLocation();
  const { user } = useAuth();
  const [isCollapsed, setIsCollapsed] = useState(false);
  const [isMobileOpen, setIsMobileOpen] = useState(false);

  const menuItems = [
    { path: '/', icon: 'fas fa-tachometer-alt', label: 'Dashboard' },
    { path: '/animals', icon: 'fas fa-paw', label: 'Animales' },
    { path: '/reproduction', icon: 'fas fa-heart', label: 'Reproducción' },
    { path: '/weights', icon: 'fas fa-weight', label: 'Pesajes' },
    { path: '/health', icon: 'fas fa-medkit', label: 'Sanidad' },
    { path: '/locations', icon: 'fas fa-map-marker-alt', label: 'Ubicaciones' },
    { path: '/finance', icon: 'fas fa-dollar-sign', label: 'Finanzas' },
    { path: '/genealogy', icon: 'fas fa-dna', label: 'Genealogía' },
    { path: '/nutrition', icon: 'fas fa-seedling', label: 'Nutrición' },
    { path: '/reports', icon: 'fas fa-chart-bar', label: 'Reportes' },
    { path: '/users', icon: 'fas fa-users', label: 'Usuarios' },
    { path: '/analytics', icon: 'fas fa-brain', label: 'Analytics' }
  ];

  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth <= 768) {
        setIsCollapsed(false);
        setIsMobileOpen(false);
      }
    };

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  return (
    <>
      {/* Mobile Hamburger Button */}
      <button
        onClick={() => setIsMobileOpen(!isMobileOpen)}
        style={{
          display: window.innerWidth <= 768 ? 'block' : 'none',
          position: 'fixed',
          top: '15px',
          left: '15px',
          zIndex: 10000,
          background: '#1a2035',
          border: 'none',
          color: '#ffffff',
          padding: '10px',
          borderRadius: '8px',
          cursor: 'pointer',
          fontSize: '16px'
        }}
      >
        <i className="fas fa-bars"></i>
      </button>

      <div 
        className="sidebar"
        style={{ 
          width: isCollapsed ? '70px' : '250px',
          transform: window.innerWidth <= 768 ? (isMobileOpen ? 'translateX(0)' : 'translateX(-100%)') : 'none'
        }}
      >
        <div style={{ padding: '20px', borderBottom: '1px solid rgba(255,255,255,0.1)', position: 'relative' }}>
          {/* Desktop Toggle */}
          {window.innerWidth > 768 && (
            <button
              onClick={() => setIsCollapsed(!isCollapsed)}
              style={{
                position: 'absolute',
                top: '15px',
                right: '15px',
                background: 'rgba(255,255,255,0.1)',
                border: 'none',
                color: '#ffffff',
                padding: '8px',
                borderRadius: '4px',
                cursor: 'pointer',
                fontSize: '14px'
              }}
            >
              <i className={`fas ${isCollapsed ? 'fa-chevron-right' : 'fa-chevron-left'}`}></i>
            </button>
          )}

          <div style={{ 
            display: 'flex', 
            alignItems: 'center', 
            gap: isCollapsed ? '0' : '12px',
            color: '#ffffff',
            fontSize: '20px',
            fontWeight: '700',
            justifyContent: isCollapsed ? 'center' : 'flex-start'
          }}>
            <div style={{
              width: '40px',
              height: '40px',
              background: 'linear-gradient(135deg, #1572e8, #0d47a1)',
              borderRadius: '8px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center'
            }}>
              <i className="fas fa-rocket" style={{ color: '#ffffff', fontSize: '18px' }}></i>
            </div>
            {!isCollapsed && <span>Kaiadmin</span>}
          </div>
          {!isCollapsed && (
            <div style={{ 
              color: 'rgba(255,255,255,0.7)', 
              fontSize: '12px',
              marginTop: '5px'
            }}>
              Sistema de Gestión Porcina
            </div>
          )}
        </div>

        <div style={{ padding: '20px 0' }}>
          {menuItems.map((item) => (
            <Link
              key={item.path}
              to={item.path}
              onClick={() => setIsMobileOpen(false)}
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: '15px',
                padding: '12px 25px',
                color: location.pathname === item.path ? '#ffffff' : 'rgba(255,255,255,0.7)',
                textDecoration: 'none',
                background: location.pathname === item.path ? 'rgba(21, 114, 232, 0.2)' : 'transparent',
                borderRight: location.pathname === item.path ? '3px solid #1572e8' : '3px solid transparent',
                transition: 'all 0.3s ease',
                fontSize: '14px',
                fontWeight: location.pathname === item.path ? '600' : '500',
                justifyContent: isCollapsed ? 'center' : 'flex-start'
              }}
              title={isCollapsed ? item.label : ''}
            >
              <i className={item.icon} style={{ fontSize: '16px', width: '20px', textAlign: 'center' }}></i>
              {!isCollapsed && <span>{item.label}</span>}
            </Link>
          ))}
        </div>

        <div style={{ 
          position: 'absolute', 
          bottom: '20px', 
          left: '20px', 
          right: '20px',
          padding: isCollapsed ? '10px' : '15px',
          background: 'rgba(255,255,255,0.1)',
          borderRadius: '8px',
          textAlign: isCollapsed ? 'center' : 'left'
        }}>
          {isCollapsed ? (
            <div style={{
              width: '30px',
              height: '30px',
              borderRadius: '50%',
              background: 'linear-gradient(135deg, #1572e8, #0d47a1)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              color: '#ffffff',
              fontSize: '12px',
              fontWeight: '600',
              margin: '0 auto'
            }}>
              {user?.nombre?.charAt(0).toUpperCase()}
            </div>
          ) : (
            <>
              <div style={{ color: '#ffffff', fontSize: '14px', fontWeight: '600' }}>
                {user?.nombre}
              </div>
              <div style={{ color: 'rgba(255,255,255,0.7)', fontSize: '12px', textTransform: 'capitalize' }}>
                {user?.rol}
              </div>
            </>
          )}
        </div>
      </div>

      {/* Mobile Overlay */}
      {isMobileOpen && (
        <div
          onClick={() => setIsMobileOpen(false)}
          style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            background: 'rgba(0,0,0,0.5)',
            zIndex: 999,
            display: window.innerWidth <= 768 ? 'block' : 'none'
          }}
        />
      )}
    </>
  );
};

export default Sidebar;
